type carBrandCountPreloader struct {
	BrandCarModels func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
}

func buildCarBrandCountPreloader() carBrandCountPreloader {
	return carBrandCountPreloader{
		BrandCarModels: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*CarBrand]("BrandCarModels", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = CarBrands.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(CarModels.Name()),
					sm.Where(psql.Quote(CarModels.Alias(), "brand_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
	}
}

