func buildCarBrandJoins[Q dialect.Joinable](cols carBrandColumns, typ string) carBrandJoins[Q] {
	return carBrandJoins[Q]{
		typ: typ,
		ManufacturerCarManufacturer: modAs[Q, carManufacturerColumns]{
			c: CarManufacturers.Columns,
			f: func(to carManufacturerColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarManufacturers.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ManufacturerID),
					))
				}

				return mods
			},
		},
		BrandCarModels: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.Name().As(to.Alias())).On(
						to.BrandID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
